module.exports = /*#__PURE__*/JSON.parse('[{"title":"Community","alias":"vt-vibe-coding-club","imageAlias":"vibe-code","headline":"VT Vibe Coding Club","timeline":"February 2026 - Present","searchDescription":"Building an inclusive student community for AI-assisted development, hands-on workshops, collaborative builds, and Vibe-a-thons at Virginia Tech.","longDescription":"VT Vibe Coding Club creates an ongoing space for students to explore programming, AI-assisted development, and emerging software tools beyond what traditional coursework usually covers. The club focuses on hands-on workshops, collaborative build sessions, and multi-day Vibe-a-thons that mirror how modern software is actually developed in industry. It also gives students a place to discuss best practices, limitations, and ethical considerations around AI tools while building stronger technical foundations through peer-driven learning.","links":[{"name":"website","url":"link-outline.svg","link":"https://vtvibe.codes/"},{"name":"Virginia Tech Website","url":"link-outline.svg","link":"https://gobblerconnect.vt.edu/organization/vibecodingatvt"}]},{"title":"Community","alias":"vt-cro","iconSrc":"/search-img/vt-cro.png","bannerSrc":"/search-img/vt-cro.png","headline":"Virginia Tech Competitive Robotics Organization","timeline":"October 2023 - Present","searchDescription":"Virginia Tech\'s largest design team, building robotics through small, dedicated teams across multiple labs and projects.","hideHero":true,"detailFirst":true,"longDescription":"","mediaFrames":[{"type":"image","src":"/search-img/vt-cro-group-pic.png","alt":"Virginia Tech Competitive Robotics Organization group picture","caption":"VT CRO Group Picture | Last Year with our Founder Marco"}],"links":[{"name":"view website","url":"link-outline.svg","link":"https://www.vtcro.org"}]},{"title":"Brave & Love","alias":"brave-love","imageAlias":"spont","headline":"Life Far From My Homeland","timeline":"July 2022 - Present","searchDescription":"There is always a second place that feels like home, I gotta adapt to a complete new world, outside of the bubble I was comforted inside.","longDescription":"Moving far from home changed how I think about identity, resilience, and belonging. It made me sharper, but also more grounded."},{"title":"Confidence","alias":"confidence","imageAlias":"tedx-cert","headline":"TEDx Speech: A Wary but Positive Look at AI","timeline":"June 20 2023","searchDescription":"From a sitting duck to a motivational speaker, I aim to ignite hearts and minds, encouraging everyone to pursue their happinesses in life.","longDescription":"Giving a TEDx talk taught me how to turn uncertainty into voice. It was one of the first moments where I felt comfortable translating big technical ideas into something human and memorable."},{"title":"Growth","alias":"growth","imageAlias":"rbc","headline":"Gap Year Before Entering College","timeline":"May 15, 2022 - August 15, 2023","searchDescription":"I explored myself in various versions. I became more free. I found peace in music. I found my soul in storytelling.","longDescription":"That period gave me room to reset my ambition, reflect more seriously, and understand what kind of life and work I actually wanted to pursue."},{"title":"Chess & Life","alias":"chess-life","imageAlias":"yyz","headline":"FIDE, USCF Chess Player","timeline":"May 2010 - Now","searchDescription":"Growing up, I realized a chess game is just like a long journey of life.","longDescription":"Chess trained patience, pattern recognition, and the willingness to make difficult moves with incomplete information. That still shows up in how I build."}]');

