module.exports = /*#__PURE__*/JSON.parse('[{"title":"Kintsugi Hearts Dream","type":"creative","alias":"kintsugi-hearts-dream","iconSrc":"/search-img/ai-mv-bts.png","bannerSrc":"/search-img/ai-mv-bts.png","headline":"AI pop music video directed and delivered end to end","timeline":"Chroma Awards 2025","searchDescription":"Directed a 4:29 AI pop music video from concept to 4K master around the theme of choosing each other in love.","longDescription":"Kintsugi Hearts Dream is a 4:29 AI pop music video I directed and delivered end to end, including concept, story, lyrics, shot plan, and final 4K master. The project centered on the message: love lasts when we keep choosing each other, even in first love. I composed and produced the duet in Suno v5 with custom structure and stems, mixed and mastered it in Ableton Live with a Novation MK3 controller, and exported release-ready versions for YouTube, Spotify, Instagram, and Facebook. I also built and ran a multi-model generative pipeline across Suno, Midjourney, OpenArt, WAN/Kling, Nanobanana, ElevenLabs, Topaz Video AI, and CapCut Pro while managing prompts, visual references, stems, and versioned assets.","tech":["Suno v5","Ableton Live","Midjourney","OpenArt","WAN","Kling","ElevenLabs","Topaz Video AI","CapCut Pro"],"videoEmbed":"https://www.youtube.com/embed/RwH7jThYDWw","mediaFrames":[{"type":"image","src":"/search-img/ai-mv-flow.png","alt":"Kintsugi Hearts Dream flow diagram","caption":"Vibe with the Flow & Rhythmic Algorithm"}],"links":[{"name":"video","url":"video-outline.svg","link":"https://youtu.be/RwH7jThYDWw"}]},{"title":"AI Hire AI","type":"hackathon","alias":"ai-hire-ai","imageAlias":"aws","headline":"Multi-agent copilot that saved 120 seconds per application","timeline":"AWS Hackathon 2026","searchDescription":"Built action-taking agents that auto-plan, prefill forms, and adapt end-to-end across job application flows.","longDescription":"Built with AWS Bedrock, Amazon Nova, Nova Act, OpenClaw, Python, TypeScript, and Docker, AI Hire AI acted as a multi-agent copilot for job applications. The system saved roughly 120 seconds per application by running applications in parallel with agents that could plan, prefill forms, and adapt actions end to end. I also built a recruiter agent that performed automatic social screening and adjusted its behavior across recruiter platforms.","tech":["AWS Bedrock","Amazon Nova","Nova Act","OpenClaw","Python","TypeScript","Docker"],"videoEmbed":"https://www.youtube.com/embed/P7I0xYGE_fA","mediaFrames":[{"type":"image","src":"/search-img/ai-hire-ai-tech-stack.png","alt":"AI Hire AI AWS hack tech stack"},{"type":"image","src":"/search-img/ai-hire-ai-flow.png","alt":"AI Hire AI flow diagram"}],"links":[{"name":"view app","url":"link-outline.svg","link":"https://ai-hire-ai.vercel.app/"},{"name":"DevPost","url":"link-outline.svg","link":"https://devpost.com/software/my-valentine"},{"name":"AWS Builder Blog","url":"link-outline.svg","link":"https://builder.aws.com/content/3B1YTR5yphTLZvPWlohlc8lkJqT/ai-hire-ai-x-amazon-nova-ai-hackathon-2026"},{"name":"video","url":"video-outline.svg","link":"https://youtu.be/P7I0xYGE_fA"}]},{"title":"AI Financial Coach","type":"hackathon","alias":"ai-financial-coach","imageAlias":"hack-princeton","headline":"AI budgeting agent with iMessage delivery","timeline":"HackPrinceton 2025","searchDescription":"Took home 3 prizes at HackPrinceton at Princeton University","longDescription":"Built with Python, Snowflake, Gemini, DigitalOcean, Node.js, React, Knot, and Photon, this AI financial coach predicted upcoming purchases and delivered personalized budgeting advice through iMessage. The product focused on practical financial guidance, timely nudges, and a more conversational user experience.","mediaFrames":[{"type":"image","src":"/search-img/hack-princeton-banner.png","alt":"AI Financial Coach at HackPrinceton"},{"type":"image","src":"/search-img/hack-prin-stack.png","alt":"AI Financial Coach tech stack"}],"tech":["Python","Snowflake","Gemini","DigitalOcean","Node.js","React","Knot","Photon"],"links":[{"name":"view post","url":"link-outline.svg","link":"https://devpost.com/software/tbd-9clz1k"}]},{"title":"Productivity Agent","type":"hackathon","alias":"productivity-agent","imageAlias":"aws","headline":"Real-time productivity agent built at AWS Hackathon","timeline":"AWS Hackathon 2025","searchDescription":"Built an agent that senses work across apps, creates concise work briefs, and recommends next-best actions.","longDescription":"Built with Python, AWS Lambda, AWS API Gateway, Nova, Bedrock, DynamoDB, and S3, this productivity agent sensed user context across apps, turned that context into concise work briefs, and recommended next-best actions. The system integrated a Chrome extension with AWS Lambda and Bedrock and increased task resumption rate by 35% by helping users re-enter work faster.","tech":["Python","AWS Lambda","AWS API Gateway","Nova","Bedrock","DynamoDB","S3"],"videoEmbed":"https://www.youtube.com/embed/o7Vgaxnxu34","links":[{"name":"video","url":"video-outline.svg","link":"https://youtu.be/o7Vgaxnxu34"}]},{"title":"AI Medical Research Tool","type":"project","alias":"ai-medical-research-tool","imageAlias":"ibm","headline":"RAG app for trustworthy, page-cited medical syntheses","timeline":"IBM Challenge 2025","searchDescription":"Built a medical research tool using watsonx.ai Granite models and parallelized retrieval across dozens of papers.","longDescription":"This RAG web app was built with Python, Flask, IBM watsonx.ai, IBM Granite, watsonx.data, and React. It generates trustworthy, page-cited medical syntheses for researchers and supports multi-document reasoning across dozens of scientific papers at once by parallelizing retrieval and context chunking through watsonx.data pipelines.","tech":["Python","Flask","IBM watsonx.ai","IBM Granite","watsonx.data","React"],"links":[]},{"title":"Deloitte Data Competition","type":"project","alias":"deloitte-data-competition","imageAlias":"deloitte","headline":"Team Winner pitching Fraud Detection Pipeline","timeline":"March 2024 - March 2026","searchDescription":"Founded and led a team for the 2024 Deloitte competition, then extended the work into a 2026 systems flowchart and architecture view.","longDescription":"For the Deloitte Data Competition, I founded and led a team of four to build a real-time fraud detection system on Azure with modeling in MATLAB and dashboards in Tableau. The 2024 project earned a Top 3 award and improved anomaly-detection precision by 22% through supervised models in Azure ML pipelines and clearer visualization of high-risk transaction clusters. In 2026, I extended the work with a dedicated system flowchart and architecture view that captured the end-to-end workflow in a clearer visual format.","tech":["Azure","MATLAB","Tableau","Azure ML","Fraud Detection","Leadership"],"mediaFrames":[{"type":"image","src":"/search-img/alexa-connect-banner.png","alt":"Deloitte Data Competition 2024 presentation"},{"type":"image","src":"/search-img/deloitte-2026-banner.png","alt":"Deloitte Data Competition 2026 flowchart"}],"links":[]},{"title":"Noteshell","type":"startup","alias":"noteshell","iconSrc":"/search-img/yc-noteshell.png","bannerSrc":"/search-img/yc-noteshell.png","headline":"Co-founder building a multimodal learning platform","timeline":"Present","searchDescription":"Top 10% Y Combinator Winter 2025 startup with personalized recommendations, an agentic study assistant, and an MCP tool layer.","longDescription":"At Noteshell, I co-founded a multimodal learning platform focused on making studying more adaptive and useful. We shipped personalized recommendations, an agentic study assistant, and an MCP tool layer that connected learning workflows into one product experience. The company was recognized in the Top 10% of Y Combinator Winter 2025.","tech":["Multimodal Systems","Agents","MCP","Recommendations","Product","Startup"],"links":[{"name":"website","url":"link-outline.svg","link":"https://app.noteshell.io"}]},{"title":"Women-first Finance Agent","type":"hackathon","alias":"ai-housing-agent","iconSrc":"/search-img/vt-hack.png","bannerSrc":"/search-img/vt-hack.png","headline":"AI finance agents for budget-aware, shared saving","timeline":"VT Capital One Hack 2026","searchDescription":"AI finance agents that live in your real-life context: capture purchases, learn your habits, find better deals, and coach you into budget-aware, shared saving.","longDescription":"Built as a women-first finance agent experience, this project focused on finance agents that live in real-life context: capturing purchases, learning user habits, finding better deals, and coaching people into budget-aware, shared saving. The product emphasized practical decision support instead of static financial dashboards.","mediaFrames":[{"type":"image","src":"/search-img/vt-hack-img1.png","alt":"Women-first Finance Agent screenshot 1"},{"type":"image","src":"/search-img/vt-hack-stack.png","alt":"Women-first Finance Agent tech stack"},{"type":"image","src":"/search-img/vt-hack-img2.png","alt":"Women-first Finance Agent screenshot 2"}],"tech":["Python","FastAPI","Postgres","pgvector","Databricks","Gemini","deck.gl","h3-js"],"links":[{"name":"view app","url":"link-outline.svg","link":"https://devpost.com/software/finance-queens"}]},{"title":"Institute for Creativity, Arts, and Technology","type":"project","alias":"icat-spatial-audio","imageAlias":"spatial-audio","bannerSrc":"/search-img/project-spatial-audio-hero.jpg","headline":"Automated Generation of Binaural Audio","timeline":"August 2025 - Present","searchDescription":"Transform any song into an immersive binaural audio experience. Got $1,000 Grant.","longDescription":"Using Whisper OpenAI, Facebook Demucs, Gemini, and our Tech Studio gears, we built an automated binaural audio pipeline.\\nThank you to all professors, mentors at ICAT VT for your support!","linksLabel":"Our Advisors","tech":["Whisper","Facebook Demucs","Python","PyTorch","Spatial Audio","Low Latency"],"mediaFrames":[{"type":"image","src":"/search-img/project-spatial-audio-hero.jpg","alt":"Spatial audio project hero"},{"type":"image","src":"/search-img/project-spatial-audio-detail.png","alt":"Spatial audio project detail"},{"type":"image","src":"/search-img/icat-loopy.png","alt":"ICAT spatial audio loopy visual"}],"links":[{"name":"Dr. Eric Lyon","url":"link-outline.svg","link":"https://sopa.vt.edu/faculty_staff/music-faculty/comp-and-creative-tech-faculty/eric-lyon.html"},{"name":"Dr. Lisa McNair","url":"link-outline.svg","link":"https://enge.vt.edu/People/researchfaculty/lisamcnair.html"},{"name":"Brandon Hale","url":"link-outline.svg","link":"https://icat.vt.edu/about/team/brandon-hale.html"},{"name":"spatialize your song","url":"link-outline.svg","link":"https://spatial-pipeline-frontend-231923493716.us-central1.run.app"}]},{"title":"Computational Neuroscience Lab at Virginia Tech (IMAGINE)","type":"project","alias":"imagine-lab","iconSrc":"/search-img/eeg-vt.jpg","bannerSrc":"/search-img/eeg-vt.jpg","headline":"EEG pipeline for musical and neurological exploration","timeline":"Jan 2024 - May 2024","searchDescription":"Built an EEG preprocessing and feature-extraction pipeline that improved motor-imagery classification accuracy by 18%.","longDescription":"As an undergraduate researcher in the IMAGINE lab, I worked on movement coding and EEG analysis to explore musical approaches for neurological research. I built an EEG preprocessing and feature-extraction pipeline in Python with MNE, applying ICA, band-pass filtering, and time-frequency features to improve motor-imagery classification accuracy by 18%.","tech":["Python","MNE","EEG","ICA","Signal Processing","Feature Extraction"],"links":[]},{"title":"Generative AI: Singing Voice Synthesis","type":"project","alias":"singing-voice-synthesis","iconSrc":"/search-img/muto-banner.png","bannerSrc":"/search-img/muto-banner.png","headline":"Speech model and data pipeline for AI-generated singing","timeline":"Nov 2023 - Mar 2024","searchDescription":"Reduced per-song time by 12 hours by automating music annotation and preprocessing pipelines.","longDescription":"Built with Python, PyTorch, and TensorBoard, this project automated music annotation and preprocessing pipelines, reducing per-song preparation time by roughly 12 hours. I also implemented a speech model in PyTorch and trained it on GPU with TensorBoard, making the workflow faster and much easier to iterate on.","tech":["Python","PyTorch","TensorBoard","GPU Training","Audio Processing"],"mediaFrames":[{"type":"image","src":"/search-img/muto-banner.png","alt":"Generative AI singing voice synthesis visual"}],"links":[]},{"title":"Meta-consciousness for Test Takers and Success Seekers","type":"project","alias":"meta-consciousness","iconSrc":"/search-img/tech-connect-banner.png","bannerSrc":"/search-img/tech-connect-banner.png","headline":"Gap-year writing project with 1,000 books published","timeline":"Oct 2022 - Jan 2024","searchDescription":"Spent a gap year writing and publishing 1,000 books with Thaihabooks and received a recommendation from the CEO.","longDescription":"During my gap year, I wrote and published 1,000 books with Thaihabooks. The project stretched both creative discipline and long-form storytelling endurance, and it led to a recommendation from the company’s CEO.","mediaFrames":[{"type":"image","src":"/search-img/tech-connect-icon.png","alt":"Meta-consciousness project visual"}],"tech":["Writing","Publishing","Storytelling","Creative Discipline"],"links":[{"name":"buy this book","url":"link-outline.svg","link":"https://thaihabooks.com/products/sieu-y-thuc-suc-manh-dan-loi-thanh-cong-toi-da-hoa-ket-qua-va-kha-nang-cua-ban-thong-qua-thien-dinh-va-khoa-hoc-tam-tri"}]}]');

